func (m *UserMutation) ResetField(name string) error {
	switch name {
	case user.FieldUsername:
		m.ResetUsername()
		return nil
	case user.FieldPasswordHash:
		m.ResetPasswordHash()
		return nil
	case user.FieldOauthProvider:
		m.ResetOauthProvider()
		return nil
	case user.FieldOauthSubject:
		m.ResetOauthSubject()
		return nil
	case user.FieldOauthEmail:
		m.ResetOauthEmail()
		return nil
	case user.FieldOauthDisplayName:
		m.ResetOauthDisplayName()
		return nil
	case user.FieldDisabled:
		m.ResetDisabled()
		return nil
	case user.FieldLastLoginAt:
		m.ResetLastLoginAt()
		return nil
	case user.FieldCreatedAt:
		m.ResetCreatedAt()
		return nil
	case user.FieldUpdatedAt:
		m.ResetUpdatedAt()
		return nil
	}
	return fmt.Errorf("unknown User field %s", name)
}

